        const val TAG = "MrdBleRingRepository"
        const val KNOWN_RING_ADDRESS = "D9:18:68:41:00:C6"
        val WRITE_SERVICE_UUID: UUID = UUID.fromString("f000efe0-0451-4000-0000-00000000b000")
