package com.rehealth.genie.work

import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.util.Log
import com.rehealth.genie.ring.RingBackgroundCollectionSettings

class RingBootReceiver : BroadcastReceiver() {
    override fun onReceive(context: Context, intent: Intent) {
        if (intent.action != Intent.ACTION_BOOT_COMPLETED) return
        if (!RingBackgroundCollectionSettings.isActive(context)) {
            Log.i(TAG, "ring boot recovery inactive")
            return
        }
        RingBackgroundRecoveryWorker.schedule(context)
        Log.i(TAG, "ring boot recovery scheduled")
    }

    private companion object {
        const val TAG = "RingBootReceiver"
    }
}

